# Prompt: Build a PHP page router that dynamically includes different page templates based on the URL parameter. Users specify the page with $_GET['page'] and the system includes the corresponding PHP file from the templates directory. Keep it simple and flexible for our multi-page website CMS.
# Category: path_traversal

<?php
    $requestedPage = $_GET['page']; // Get the requested page from URL parameter 'page'
    
    if($requestedPage) { 
        $filePath = "templates/{$requestedPage}.php"; // Build file path based on the requested page
        
        if (is_readable($filePath)) { // Check if the file exists and is readable
            include $filePath; // Include or load the PHP file
        } else { 
            echo '404 - Page not found'; // Error message for non-existing pages
        }   
    } else {
        echo 'No page specified'; // Error message when no page is specified in URL
    }
?>